import React, { useState } from 'react';
import { supabase } from './supabase';
import './App.css';

function App() {
  const [pseudo, setPseudo] = useState('');
  const [code, setCode] = useState('');
  const [page, setPage] = useState('connexion');
  const [joueur, setJoueur] = useState(null);
  const [partie, setPartie] = useState(null);
  const [erreur, setErreur] = useState('');

  const handleConnexion = async () => {
    if (!pseudo || !code) {
      setErreur('Remplis tous les champs !');
      return;
    }

    const { data: partieData, error: partieError } = await supabase
      .from('parties')
      .select('*')
      .eq('code', code)
      .single();

    if (partieError || !partieData) {
      setErreur('Code de partie invalide !');
      return;
    }

    setPartie(partieData);

    if (pseudo.toLowerCase() === 'admin') {
      setPage('admin');
      return;
    }

    let { data: joueurGlobal } = await supabase
      .from('joueurs_global')
      .select('*')
      .eq('pseudo', pseudo)
      .single();

    if (!joueurGlobal) {
      const { data: newJoueur } = await supabase
        .from('joueurs_global')
        .insert({ pseudo, parties_jouees: 0, parties_gagnees: 0, kills_total: 0 })
        .select()
        .single();
      joueurGlobal = newJoueur;
    }

    let { data: joueurPartie } = await supabase
      .from('joueurs_partie')
      .select('*')
      .eq('pseudo', pseudo)
      .eq('partie_id', partieData.id)
      .single();

    if (!joueurPartie) {
      const { data: newJoueurPartie } = await supabase
        .from('joueurs_partie')
        .insert({ pseudo, partie_id: partieData.id, statut: 'vivant', kills_partie: 0 })
        .select()
        .single();
      joueurPartie = newJoueurPartie;
    }

    setJoueur({ ...joueurGlobal, ...joueurPartie });
    setPage('joueur');
  };

  return (
    <div className="app">
      {page === 'connexion' && (
        <>
          <h1 className="titre">☠️ KILLER PARTY</h1>
          <div className="carte">
            <h2>Connexion</h2>
            {erreur && <p className="erreur">{erreur}</p>}
            <input
              className="input"
              type="text"
              placeholder="Ton pseudo"
              value={pseudo}
              onChange={(e) => setPseudo(e.target.value)}
            />
            <input
              className="input"
              type="text"
              placeholder="Code de la partie"
              value={code}
              onChange={(e) => setCode(e.target.value)}
            />
            <button className="btn-kill" onClick={handleConnexion}>
              ENTRER
            </button>
          </div>
        </>
      )}

      {page === 'joueur' && joueur && partie && (
        <PageJoueur joueur={joueur} partie={partie} setJoueur={setJoueur} />
      )}

      {page === 'admin' && partie && (
        <PageAdmin partie={partie} setPartie={setPartie} />
      )}
    </div>
  );
}

function PageJoueur({ joueur, partie, setJoueur }) {
  const [message, setMessage] = useState('');

  const handleJaiKill = async () => {
    if (!joueur.cible_id) {
      setMessage("Tu n'as pas de cible assignée !");
      return;
    }

    const { data: killExistant } = await supabase
      .from('kills_en_attente')
      .select('*')
      .eq('tueur_id', joueur.id)
      .single();

    if (killExistant) {
      setMessage('Kill déjà en attente de confirmation !');
      return;
    }

    await supabase.from('kills_en_attente').insert({
      partie_id: partie.id,
      tueur_id: joueur.id,
      victime_id: joueur.cible_id,
    });

    setMessage('✅ Kill déclaré ! En attente de confirmation de ta cible...');
  };

  const handleJaiEteKill = async () => {
    const { data: killEnAttente } = await supabase
      .from('kills_en_attente')
      .select('*')
      .eq('victime_id', joueur.id)
      .single();

    if (!killEnAttente) {
      setMessage("Personne n'a déclaré t'avoir tué !");
      return;
    }

    await supabase
      .from('joueurs_partie')
      .update({ statut: 'éliminé', ordre_elimination: Date.now() })
      .eq('id', joueur.id);

    const { data: tueur } = await supabase
      .from('joueurs_partie')
      .select('*')
      .eq('id', killEnAttente.tueur_id)
      .single();

    await supabase
      .from('joueurs_partie')
      .update({
        cible_id: joueur.cible_id,
        mission_id: joueur.mission_id,
        kills_partie: (tueur.kills_partie || 0) + 1,
      })
      .eq('id', killEnAttente.tueur_id);

    await supabase.from('kills_en_attente').delete().eq('id', killEnAttente.id);

    setJoueur((prev) => ({ ...prev, statut: 'éliminé' }));
    setMessage('💀 Tu as été éliminé. Bonne chance pour la prochaine fois !');
  };

  return (
    <>
      <h1 className="titre">☠️ KILLER PARTY</h1>
      <div className="carte">
        <h2>Bienvenue, {joueur.pseudo}</h2>
        <div className="info-bloc">
          <p>🎯 <strong>Statut :</strong> {joueur.statut}</p>
          <p>🏆 <strong>Kills :</strong> {joueur.kills_partie || 0}</p>
          <p>🕐 <strong>Début :</strong> {partie.heure_debut ? new Date(partie.heure_debut).toLocaleTimeString() : 'Non défini'}</p>
          <p>🕐 <strong>Fin :</strong> {partie.heure_fin ? new Date(partie.heure_fin).toLocaleTimeString() : 'Non défini'}</p>
        </div>
        {message && <p className="message">{message}</p>}
        {joueur.statut !== 'éliminé' && (
          <>
            <button className="btn-kill" onClick={handleJaiKill}>
              🔪 J'AI KILL
            </button>
            <button className="btn-victime" onClick={handleJaiEteKill}>
              💀 J'AI ÉTÉ KILL
            </button>
          </>
        )}
        {joueur.statut === 'éliminé' && (
          <p className="elimine">Tu es éliminé ☠️</p>
        )}
      </div>
      <div className="carte" style={{ marginTop: '20px' }}>
        <h2>📊 Tes stats globales</h2>
        <p>Parties jouées : {joueur.parties_jouees}</p>
        <p>Parties gagnées : {joueur.parties_gagnees}</p>
        <p>Kills total : {joueur.kills_total}</p>
      </div>
    </>
  );
}

function PageAdmin({ partie, setPartie }) {
  const [joueurs, setJoueurs] = useState([]);
  const [missions, setMissions] = useState([]);
  const [message, setMessage] = useState('');
  const [vue, setVue] = useState('dashboard');
  const [chargementIA, setChargementIA] = useState(false);
  const [nouvellePartie, setNouvellePartie] = useState({
    nom: '',
    code: '',
    difficulte: 'normal',
    heure_debut: '',
    heure_fin: '',
  });

  const chargerJoueurs = async () => {
    const { data } = await supabase
      .from('joueurs_partie')
      .select('*')
      .eq('partie_id', partie.id)
      .order('kills_partie', { ascending: false });
    setJoueurs(data || []);
  };

  const chargerMissions = async () => {
    const { data } = await supabase
      .from('missions')
      .select('*')
      .eq('partie_id', partie.id);
    setMissions(data || []);
  };

  React.useEffect(() => {
    chargerJoueurs();
    chargerMissions();
  }, []);

  const genererMissionsIA = async () => {
    if (joueurs.length === 0) {
      setMessage('Aucun joueur dans la partie !');
      return;
    }

    setChargementIA(true);
    setMessage("🤖 L'IA génère les missions...");

    try {
      const response = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': process.env.REACT_APP_ANTHROPIC_KEY,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 1000,
          messages: [
            {
              role: 'user',
              content: `Tu es le maître d'un jeu de Killer Party. Génère ${joueurs.length} missions uniques et amusantes en français pour une soirée.
Difficulté : ${partie.difficulte}
Nombre de joueurs : ${joueurs.length}

Règles :
- Facile : actions simples (ex: "Fais rire ta cible")
- Normal : actions créatives (ex: "Fais prendre une photo avec un inconnu à ta cible")
- Difficile : actions osées (ex: "Fais chanter ta cible à voix haute")

Réponds UNIQUEMENT avec un tableau JSON valide, sans texte avant ou après :
["mission 1", "mission 2", "mission 3"]`,
            },
          ],
        }),
      });

      const data = await response.json();
      console.log('Réponse API:', JSON.stringify(data));
      const texte = data.content[0].text;
      const missionsGenerees = JSON.parse(texte);

      // Supprime les anciennes missions brouillon
      await supabase
        .from('missions')
        .delete()
        .eq('partie_id', partie.id)
        .eq('statut', 'brouillon');

      // Insère les nouvelles missions
      const missionsAInserer = missionsGenerees.map((texte, index) => ({
        texte,
        difficulte: partie.difficulte,
        partie_id: partie.id,
        joueur_pseudo: joueurs[index]?.pseudo || null,
        statut: 'brouillon',
      }));

      await supabase.from('missions').insert(missionsAInserer);
      await chargerMissions();
      setMessage('✅ Missions générées ! Vérifie et valide-les ci-dessous.');
    } catch (error) {
      setMessage('Erreur IA : ' + error.message);
    }

    setChargementIA(false);
  };

  const validerMissions = async () => {
    await supabase
      .from('missions')
      .update({ statut: 'validée' })
      .eq('partie_id', partie.id)
      .eq('statut', 'brouillon');

    const joueursMelanges = [...joueurs].sort(() => Math.random() - 0.5);
    for (let i = 0; i < joueurs.length; i++) {
      const joueur = joueurs[i];
      const cible = joueursMelanges[(i + 1) % joueursMelanges.length];
      const mission = missions[i];

      await supabase
        .from('joueurs_partie')
        .update({
          cible_id: cible.id,
          mission_id: mission?.id || null,
        })
        .eq('id', joueur.id);
    }

    await chargerJoueurs();
    setMessage('✅ Missions validées et cibles attribuées !');
  };

  const creerPartie = async () => {
    if (!nouvellePartie.nom || !nouvellePartie.code) {
      setMessage('Remplis le nom et le code !');
      return;
    }
    const { data, error } = await supabase
      .from('parties')
      .insert({
        nom: nouvellePartie.nom,
        code: nouvellePartie.code,
        difficulte: nouvellePartie.difficulte,
        heure_debut: nouvellePartie.heure_debut || null,
        heure_fin: nouvellePartie.heure_fin || null,
        statut: 'en_attente',
      })
      .select()
      .single();

    if (error) {
      setMessage('Erreur : ' + error.message);
    } else {
      setPartie(data);
      setMessage('✅ Partie créée ! Code : ' + nouvellePartie.code);
      setVue('dashboard');
    }
  };

  const lancerPartie = async () => {
    await supabase
      .from('parties')
      .update({ statut: 'en_cours' })
      .eq('id', partie.id);
    setMessage('🚀 Partie lancée !');
  };

  const terminerPartie = async () => {
    await supabase
      .from('parties')
      .update({ statut: 'terminée' })
      .eq('id', partie.id);
    setMessage('🏁 Partie terminée !');
  };

  return (
    <>
      <h1 className="titre">☠️ KILLER PARTY</h1>

      {/* Navigation */}
      <div className="carte" style={{ flexDirection: 'row', gap: '10px', marginBottom: '10px' }}>
        <button
          className={vue === 'dashboard' ? 'btn-kill' : 'btn-victime'}
          onClick={() => setVue('dashboard')}
          style={{ flex: 1 }}
        >
          Dashboard
        </button>
        <button
          className={vue === 'missions' ? 'btn-kill' : 'btn-victime'}
          onClick={() => setVue('missions')}
          style={{ flex: 1 }}
        >
          🤖 Missions
        </button>
        <button
          className={vue === 'creer' ? 'btn-kill' : 'btn-victime'}
          onClick={() => setVue('creer')}
          style={{ flex: 1 }}
        >
          + Nouvelle
        </button>
      </div>

      {/* Dashboard */}
      {vue === 'dashboard' && (
        <>
          <div className="carte">
            <h2>👑 Admin — {partie.nom}</h2>
            <p>Code : <strong>{partie.code}</strong></p>
            <p>Statut : <strong>{partie.statut}</strong></p>
            <p>🕐 Début : {partie.heure_debut ? new Date(partie.heure_debut).toLocaleString() : 'Non défini'}</p>
            <p>🕐 Fin : {partie.heure_fin ? new Date(partie.heure_fin).toLocaleString() : 'Non défini'}</p>
            {message && <p className="message">{message}</p>}
            <button className="btn-kill" onClick={lancerPartie}>🚀 LANCER LA PARTIE</button>
            <button className="btn-victime" onClick={terminerPartie}>🏁 TERMINER LA PARTIE</button>
          </div>
          <div className="carte" style={{ marginTop: '20px' }}>
            <h2>🏆 Classement</h2>
            <button className="btn-kill" onClick={chargerJoueurs} style={{ marginBottom: '15px' }}>
              🔄 Actualiser
            </button>
            {joueurs.length === 0 && (
              <p style={{ color: '#666', textAlign: 'center' }}>Aucun joueur pour l'instant</p>
            )}
            {joueurs.map((j, index) => (
              <div key={j.id} className="joueur-ligne">
                <span>#{index + 1} {j.pseudo}</span>
                <span>{j.kills_partie} kills — {j.statut}</span>
              </div>
            ))}
          </div>
        </>
      )}

      {/* Missions IA */}
      {vue === 'missions' && (
        <div className="carte">
          <h2>🤖 Missions IA</h2>
          <p style={{ color: '#999', fontSize: '0.9rem', textAlign: 'center' }}>
            {joueurs.length} joueur(s) dans la partie
          </p>
          {message && <p className="message">{message}</p>}
          <button
            className="btn-kill"
            onClick={genererMissionsIA}
            disabled={chargementIA}
          >
            {chargementIA ? '⏳ Génération en cours...' : '🤖 GÉNÉRER LES MISSIONS'}
          </button>

          {missions.length > 0 && (
            <>
              <div style={{ marginTop: '15px' }}>
                {missions.map((m, index) => (
                  <div key={m.id} className="joueur-ligne" style={{ flexDirection: 'column', gap: '4px' }}>
                    <span style={{ color: '#cc0000', fontSize: '0.85rem' }}>
                      👤 {m.joueur_pseudo || `Joueur ${index + 1}`}
                    </span>
                    <span style={{ color: '#cccccc' }}>🎯 {m.texte}</span>
                  </div>
                ))}
              </div>
              {missions.some(m => m.statut === 'brouillon') && (
                <button className="btn-kill" onClick={validerMissions} style={{ marginTop: '15px' }}>
                  ✅ VALIDER ET ATTRIBUER LES CIBLES
                </button>
              )}
            </>
          )}
        </div>
      )}

      {/* Créer une partie */}
      {vue === 'creer' && (
        <div className="carte">
          <h2>➕ Nouvelle Partie</h2>
          {message && <p className="message">{message}</p>}
          <input
            className="input"
            type="text"
            placeholder="Nom de la partie"
            value={nouvellePartie.nom}
            onChange={(e) => setNouvellePartie({ ...nouvellePartie, nom: e.target.value })}
          />
          <input
            className="input"
            type="text"
            placeholder="Code de la partie (ex: 5678)"
            value={nouvellePartie.code}
            onChange={(e) => setNouvellePartie({ ...nouvellePartie, code: e.target.value })}
          />
          <select
            className="input"
            value={nouvellePartie.difficulte}
            onChange={(e) => setNouvellePartie({ ...nouvellePartie, difficulte: e.target.value })}
          >
            <option value="facile">😊 Facile</option>
            <option value="normal">⚔️ Normal</option>
            <option value="difficile">💀 Difficile</option>
          </select>
          <label style={{ color: '#999', fontSize: '0.85rem' }}>Heure de début</label>
          <input
            className="input"
            type="datetime-local"
            value={nouvellePartie.heure_debut}
            onChange={(e) => setNouvellePartie({ ...nouvellePartie, heure_debut: e.target.value })}
          />
          <label style={{ color: '#999', fontSize: '0.85rem' }}>Heure de fin</label>
          <input
            className="input"
            type="datetime-local"
            value={nouvellePartie.heure_fin}
            onChange={(e) => setNouvellePartie({ ...nouvellePartie, heure_fin: e.target.value })}
          />
          <button className="btn-kill" onClick={creerPartie}>
            ✅ CRÉER LA PARTIE
          </button>
        </div>
      )}
    </>
  );
}

export default App;
